/// This test MUST demonstrate DPOR's value
#[test]
fn test_dpor_finds_rare_race() {
    // A bug that random testing with 10,000 seeds doesn't find
    // but DPOR finds deterministically

    // 1. Run with random testing
    let mut found_with_random = false;
    for seed in 0..10_000 {
        let lab = LabRuntime::new(LabConfig::default().seed(seed));
        let result = lab.run(buggy_program);
        if result.is_err() {
            found_with_random = true;
            break;
        }
    }

    info\!(
        method = 'random',
        seeds_tried = 10_000,
        bug_found = found_with_random,
        'Random testing result'
    );

    // 2. Run with DPOR
    let explorer = ScheduleExplorer::new(ExplorerConfig::default());
    let result = explorer.explore(buggy_program);

    info\!(
        method = 'dpor',
        schedules_explored = result.schedules_explored,
        bugs_found = result.bugs.len(),
        'DPOR result'
    );

    // DPOR MUST find the bug
    assert\!(\!result.bugs.is_empty(), 'DPOR should find bug');

    // Document the advantage
    info\!(
        random_seeds = 10_000,
        dpor_schedules = result.schedules_explored,
        'DPOR found bug that random missed'
    );
}
